974:     private Future<RecordMetadata> doSend(ProducerRecord<K, V> record, Callback callback) {
975:         // Append callback takes care of the following:
976:         //  - call interceptors and user callback on completion
977:         //  - remember partition that is calculated in RecordAccumulator.append
978:         AppendCallbacks appendCallbacks = new AppendCallbacks(callback, this.interceptors, record);
979: 
980:         try {
981:             throwIfProducerClosed();
982:             throwIfInPreparedState();
983: 
984:             // first make sure the metadata for the topic is available
985:             long nowMs = time.milliseconds();
986:             ClusterAndWaitTime clusterAndWaitTime;
987:             try {
988:                 clusterAndWaitTime = waitOnMetadata(record.topic(), record.partition(), nowMs, maxBlockTimeMs);
989:             } catch (KafkaException e) {
990:                 if (metadata.isClosed())
991:                     throw new KafkaException("Producer closed while send in progress", e);
992:                 throw e;
993:             }
994:             nowMs += clusterAndWaitTime.waitedOnMetadataMs;
995:             long remainingWaitMs = Math.max(0, maxBlockTimeMs - clusterAndWaitTime.waitedOnMetadataMs);
996:             Cluster cluster = clusterAndWaitTime.cluster;
997:             byte[] serializedKey;
998:             try {
999:                 serializedKey = keySerializerPlugin.get().serialize(record.topic(), record.headers(), record.key());
1000:             } catch (ClassCastException cce) {
1001:                 throw new SerializationException("Can't convert key of class " + record.key().getClass().getName() +
1002:                         " to class " + producerConfig.getClass(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG).getName() +
1003:                         " specified in key.serializer", cce);
1004:             }
1005:             byte[] serializedValue;
1006:             try {
1007:                 serializedValue = valueSerializerPlugin.get().serialize(record.topic(), record.headers(), record.value());
1008:             } catch (ClassCastException cce) {
1009:                 throw new SerializationException("Can't convert value of class " + record.value().getClass().getName() +
1010:                         " to class " + producerConfig.getClass(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG).getName() +
1011:                         " specified in value.serializer", cce);
1012:             }
1013: 
1014:             // Try to calculate partition, but note that after this call it can be RecordMetadata.UNKNOWN_PARTITION,
1015:             // which means that the RecordAccumulator would pick a partition using built-in logic (which may
1016:             // take into account broker load, the amount of data produced to each partition, etc.).
1017:             int partition = partition(record, serializedKey, serializedValue, cluster);
1018: 
1019:             setReadOnly(record.headers());
1020:             Header[] headers = record.headers().toArray();
1021: 
1022:             int serializedSize = AbstractRecords.estimateSizeInBytesUpperBound(RecordBatch.CURRENT_MAGIC_VALUE,
1023:                     compression.type(), serializedKey, serializedValue, headers);
1024:             ensureValidRecordSize(serializedSize);
1025:             long timestamp = record.timestamp() == null ? nowMs : record.timestamp();
1026: 
1027:             // Append the record to the accumulator.  Note, that the actual partition may be
1028:             // calculated there and can be accessed via appendCallbacks.topicPartition.
1029:             RecordAccumulator.RecordAppendResult result = accumulator.append(record.topic(), partition, timestamp, serializedKey,
1030:                     serializedValue, headers, appendCallbacks, remainingWaitMs, nowMs, cluster);
1031:             assert appendCallbacks.getPartition() != RecordMetadata.UNKNOWN_PARTITION;
1032: 
1033:             // Add the partition to the transaction (if in progress) after it has been successfully
1034:             // appended to the accumulator. We cannot do it before because the partition may be
1035:             // unknown. Note that the `Sender` will refuse to dequeue
1036:             // batches from the accumulator until they have been added to the transaction.
1037:             if (transactionManager != null) {
1038:                 transactionManager.maybeAddPartition(appendCallbacks.topicPartition());
1039:             }
1040: 
1041:             if (result.batchIsFull || result.newBatchCreated) {
1042:                 log.trace("Waking up the sender since topic {} partition {} is either full or getting a new batch", record.topic(), appendCallbacks.getPartition());
1043:                 this.sender.wakeup();
1044:             }
1045:             return result.future;
1046:             // handling exceptions and record the errors;
