275:     public RecordAppendResult append(String topic,
276:                                      int partition,
277:                                      long timestamp,
278:                                      byte[] key,
279:                                      byte[] value,
280:                                      Header[] headers,
281:                                      AppendCallbacks callbacks,
282:                                      long maxTimeToBlock,
283:                                      long nowMs,
284:                                      Cluster cluster) throws InterruptedException {
285:         TopicInfo topicInfo = topicInfoMap.computeIfAbsent(topic, k -> new TopicInfo(createBuiltInPartitioner(logContext, k, batchSize)));
286: 
287:         // We keep track of the number of appending thread to make sure we do not miss batches in
288:         // abortIncompleteBatches().
289:         appendsInProgress.incrementAndGet();
290:         ByteBuffer buffer = null;
291:         if (headers == null) headers = Record.EMPTY_HEADERS;
292:         try {
293:             // Loop to retry in case we encounter partitioner's race conditions.
294:             while (true) {
295:                 // If the message doesn't have any partition affinity, so we pick a partition based on the broker
296:                 // availability and performance.  Note, that here we peek current partition before we hold the
297:                 // deque lock, so we'll need to make sure that it's not changed while we were waiting for the
298:                 // deque lock.
299:                 final BuiltInPartitioner.StickyPartitionInfo partitionInfo;
300:                 final int effectivePartition;
301:                 if (partition == RecordMetadata.UNKNOWN_PARTITION) {
302:                     partitionInfo = topicInfo.builtInPartitioner.peekCurrentPartitionInfo(cluster);
303:                     effectivePartition = partitionInfo.partition();
304:                 } else {
305:                     partitionInfo = null;
306:                     effectivePartition = partition;
307:                 }
308: 
309:                 // Now that we know the effective partition, let the caller know.
310:                 setPartition(callbacks, effectivePartition);
311: 
312:                 // check if we have an in-progress batch
313:                 Deque<ProducerBatch> dq = topicInfo.batches.computeIfAbsent(effectivePartition, k -> new ArrayDeque<>());
314:                 synchronized (dq) {
315:                     // After taking the lock, validate that the partition hasn't changed and retry.
316:                     if (partitionChanged(topic, topicInfo, partitionInfo, dq, nowMs, cluster))
317:                         continue;
318: 
319:                     RecordAppendResult appendResult = tryAppend(timestamp, key, value, headers, callbacks, dq, nowMs);
320:                     if (appendResult != null) {
321:                         // If queue has incomplete batches we disable switch (see comments in updatePartitionInfo).
322:                         boolean enableSwitch = allBatchesFull(dq);
323:                         topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, appendResult.appendedBytes, cluster, enableSwitch);
324:                         return appendResult;
325:                     }
326:                 }
327: 
328:                 if (buffer == null) {
329:                     int size = Math.max(this.batchSize, AbstractRecords.estimateSizeInBytesUpperBound(
330:                             RecordBatch.CURRENT_MAGIC_VALUE, compression.type(), key, value, headers));
331:                     log.trace("Allocating a new {} byte message buffer for topic {} partition {} with remaining timeout {}ms", size, topic, effectivePartition, maxTimeToBlock);
332:                     // This call may block if we exhausted buffer space.
333:                     buffer = free.allocate(size, maxTimeToBlock);
334:                     // Update the current time in case the buffer allocation blocked above.
335:                     // NOTE: getting time may be expensive, so calling it under a lock
336:                     // should be avoided.
337:                     nowMs = time.milliseconds();
338:                 }
339: 
340:                 synchronized (dq) {
341:                     // After taking the lock, validate that the partition hasn't changed and retry.
342:                     if (partitionChanged(topic, topicInfo, partitionInfo, dq, nowMs, cluster))
343:                         continue;
344: 
345:                     RecordAppendResult appendResult = appendNewBatch(topic, effectivePartition, dq, timestamp, key, value, headers, callbacks, buffer, nowMs);
346:                     // Set buffer to null, so that deallocate doesn't return it back to free pool, since it's used in the batch.
347:                     if (appendResult.newBatchCreated)
348:                         buffer = null;
349:                     // If queue has incomplete batches we disable switch (see comments in updatePartitionInfo).
350:                     boolean enableSwitch = allBatchesFull(dq);
351:                     topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, appendResult.appendedBytes, cluster, enableSwitch);
352:                     return appendResult;
353:                 }
354:             }
355:         } finally {
356:             free.deallocate(buffer);
357:             appendsInProgress.decrementAndGet();
358:         }
359:     }
