357:     private long sendProducerData(long now) {
358:         MetadataSnapshot metadataSnapshot = metadata.fetchMetadataSnapshot();
359:         // get the list of partitions with data ready to send
360:         RecordAccumulator.ReadyCheckResult result = this.accumulator.ready(metadataSnapshot, now);
361: 
362:         // if there are any partitions whose leaders are not known yet, force metadata update
363:         if (!result.unknownLeaderTopics.isEmpty()) {
364:             // The set of topics with unknown leader contains topics with leader election pending as well as
365:             // topics which may have expired. Add the topic again to metadata to ensure it is included
366:             // and request metadata update, since there are messages to send to the topic.
367:             for (String topic : result.unknownLeaderTopics)
368:                 this.metadata.add(topic, now);
369: 
370:             log.debug("Requesting metadata update due to unknown leader topics from the batched records: {}",
371:                 result.unknownLeaderTopics);
372:             this.metadata.requestUpdate(false);
373:         }
374: 
375:         // remove any nodes we aren't ready to send to
376:         Iterator<Node> iter = result.readyNodes.iterator();
377:         long notReadyTimeout = Long.MAX_VALUE;
378:         while (iter.hasNext()) {
379:             Node node = iter.next();
380:             if (!this.client.ready(node, now)) {
381:                 // Update just the readyTimeMs of the latency stats, so that it moves forward
382:                 // every time the batch is ready (then the difference between readyTimeMs and
383:                 // drainTimeMs would represent how long data is waiting for the node).
